/*!40111 SET @OLD_SQL_NOTES=@@SQL_NOTES, SQL_NOTES=0 */;


-- studycafe 데이터베이스 구조 내보내기
DROP DATABASE IF EXISTS `studycafe`;
CREATE DATABASE IF NOT EXISTS `studycafe`;
USE `studycafe`;

-- 테이블 studycafe.sc_payment 구조 내보내기
DROP TABLE IF EXISTS `sc_payment`;
CREATE TABLE IF NOT EXISTS `sc_payment` (
  `rectno` varchar(50) NOT NULL COMMENT '영수증No',
  `usr_phnumber` varchar(20) NOT NULL COMMENT '(이용자)전화번호',
  `svc_cd` varchar(20) NOT NULL COMMENT '상품코드',
  `pay_dt` datetime NOT NULL COMMENT '결제일시',
  `pay_amt` int(10) unsigned NOT NULL DEFAULT 0 COMMENT '결제금액',
  PRIMARY KEY (`rectno`) USING BTREE,
  UNIQUE KEY `UIDX1` (`usr_phnumber`,`svc_cd`,`pay_dt`) USING BTREE,
  KEY `FK1` (`usr_phnumber`) USING BTREE,
  KEY `FK2` (`svc_cd`) USING BTREE,
  CONSTRAINT `FK_sc_payment_sc_service` FOREIGN KEY (`svc_cd`) REFERENCES `sc_service` (`svc_cd`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `FK_sc_payment_sc_user` FOREIGN KEY (`usr_phnumber`) REFERENCES `sc_user` (`usr_phnumber`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB COMMENT='결제(구매)정보';

-- 테이블 데이터 studycafe.sc_payment:~1,680 rows (대략적) 내보내기

-- 테이블 studycafe.sc_seat 구조 내보내기
DROP TABLE IF EXISTS `sc_seat`;
CREATE TABLE IF NOT EXISTS `sc_seat` (
  `seat_no` int(3) NOT NULL COMMENT '좌석번호',
  `occupied` varchar(20) DEFAULT NULL COMMENT '점유된 고객 전화번호',
  `lastupdate` datetime DEFAULT NULL COMMENT '최근 업데이트 일시',
  PRIMARY KEY (`seat_no`) USING BTREE
) ENGINE=InnoDB COMMENT='좌석정보';

-- 테이블 데이터 studycafe.sc_seat:~25 rows (대략적) 내보내기

-- 테이블 studycafe.sc_service 구조 내보내기
DROP TABLE IF EXISTS `sc_service`;
CREATE TABLE IF NOT EXISTS `sc_service` (
  `svc_cd` varchar(20) NOT NULL COMMENT '상품코드',
  `svc_nm` varchar(100) NOT NULL COMMENT '상품명',
  `svc_grpcd` varchar(20) NOT NULL COMMENT '상품그룹코드\r\n1일권=''a''/자유권=''b''/정기권=''c''\r\n스터디룸 대여=''d''/사물함 대여=''e''',
  `svc_desc` varchar(1000) DEFAULT NULL COMMENT '상세설명',
  `svc_duration` int(10) unsigned NOT NULL COMMENT '사용기한, 분(min)으로 환산한 값',
  `svc_cost` int(10) unsigned NOT NULL COMMENT '상품금액, 원화(KW)',
  PRIMARY KEY (`svc_cd`) USING BTREE
) ENGINE=InnoDB COMMENT='서비스(상품)정보';

-- 테이블 데이터 studycafe.sc_service:~18 rows (대략적) 내보내기

-- 테이블 studycafe.sc_user 구조 내보내기
DROP TABLE IF EXISTS `sc_user`;
CREATE TABLE IF NOT EXISTS `sc_user` (
  `usr_phnumber` varchar(20) NOT NULL COMMENT '(이용자)전화번호',
  `seat_no` int(3) DEFAULT NULL COMMENT '사용 중인 좌석번호',
  `svc_cd` varchar(20) DEFAULT NULL COMMENT '사용 중인 서비스(상품)코드',
  `use_starttime` datetime DEFAULT NULL COMMENT '최근 입실시각',
  `use_endtime` datetime DEFAULT NULL COMMENT '최근 퇴실시각',
  PRIMARY KEY (`usr_phnumber`) USING BTREE,
  KEY `FK_sc_user_sc_seat` (`seat_no`),
  KEY `FK_sc_user_sc_service` (`svc_cd`),
  CONSTRAINT `FK_sc_user_sc_seat` FOREIGN KEY (`seat_no`) REFERENCES `sc_seat` (`seat_no`) ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT `FK_sc_user_sc_service` FOREIGN KEY (`svc_cd`) REFERENCES `sc_service` (`svc_cd`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB COMMENT='고객(회원)정보';

-- 테이블 데이터 studycafe.sc_user:~40 rows (대략적) 내보내기

